INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (389, '12 Angry Men', 1957, 97, 'United States of America', 'English', 'The defense and the prosecution have rested and the jury is filing into the jury room to decide if a young Spanish-American is guilty or innocent of murdering his father. What begins as an open and shut case soon becomes a mini-drama of each of the jurors'' prejudices and preconceptions about the trial, the accused, and each other.', 'https://image.tmdb.org/t/p/w500/zhG3vKWyDRaZYoaww1UVAi29T9h.jpg', 'https://image.tmdb.org/t/p/original/w4bTBXcqXc2TUyS5Fc4h67uWbPn.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
