INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (155, 'The Dark Knight', 2008, 152, 'United Kingdom', 'English', 'Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.', 'https://image.tmdb.org/t/p/w500/qJ2tW6WMUDux911r6m7haRef0WH.jpg', 'https://image.tmdb.org/t/p/original/cfT29Im5VDvjE0RpyKOSdCKZal7.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
