INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1390382, 'Couture', 2026, 106, 'France', 'French', 'In the frenzy of Fashion Week, three women cross paths in Paris, grappling with the world''s tragedies and the questions of their lives: Maxine, an American film director in her forties, discovers she has cancer; Ada, a young South Sudanese model, escapes a predetermined destiny to be thrust into a deceptive universe and French makeup artist Angèle, a small hand working in the shadows of the catwalks, dreams of escaping her life.', 'https://image.tmdb.org/t/p/w500/jhdWrG2KebrnIbHd3UJpcpX1feE.jpg', 'https://image.tmdb.org/t/p/original/7MtfQcyAYD8xUtnr2kei9phnt8M.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
