INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (25237, 'Come and See', 1985, 142, 'Soviet Union', 'Belarusian', 'The invasion of a village in Belarus by German forces sends young Florya into the forest to join the weary Resistance fighters, against his family''s wishes. There he meets a girl, Glasha, who accompanies him back to his village. On returning home, Florya finds his family and fellow peasants massacred. His continued survival amidst the brutal debris of war becomes increasingly nightmarish, a battle between despair and hope.', 'https://image.tmdb.org/t/p/w500/qNbMsKVzigERgJUbwf8pKyZogpb.jpg', 'https://image.tmdb.org/t/p/original/3Na31ta8vDuKOgQuPLdSZLs8bCB.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
