INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1359607, 'Miss Kobayashi''s Dragon Maid: A lonely dragon wants to be loved', 2025, 104, 'Japan', 'Japanese', 'Miss Kobayashi, Tohru, Kanna, and Iruru''s peaceful lives are shattered when Kanna''s father, Kimun Kamui, leader of the Chaos Forces, arrives and forces her to return to the Dragon World to fix a past mistake. With a war brewing between Chaos and Harmony, Kanna must find a way to unite the two worlds but is torn between her loyalty to her friends and her father''s demands. Miss Kobayashi, however, refuses to let her go and tries to mend Kanna and Kamui''s broken bond. As dragons clash, Iruru uncovers a hidden force manipulating the war. Can they stop the war before it consumes both worlds?', 'https://image.tmdb.org/t/p/w500/kN0V877loq6kkDybVbi3KcrjwgE.jpg', 'https://image.tmdb.org/t/p/original/nBKrBDxNx10SuAKPLRtBXoRku5y.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
