INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1278853, 'Woodwalkers 2', 2026, 102, 'Austria', 'German', 'For shapeshifter Carag and his friends Brandon, Holly, and Lou, a new school year begins at Clearwater High. But first, the Woodwalker Council must decide whether Carag''s mentor and patron of the school, Andrew Milling, is guilty of attacking humans. Carag is in a dilemma: he wants to put a stop to Milling''s actions, but Milling promises to take him to his true puma family if he covers for him before the council.', 'https://image.tmdb.org/t/p/w500/9WrGxlyXnoV0ecLiA76wNaga8pK.jpg', 'https://image.tmdb.org/t/p/original/sueKcqeTG4tk7yeDXCHDvkYS8rl.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
