INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (441130, 'Wolfwalkers', 2020, 102, 'France', 'English', 'In a time of superstition and magic, when wolves are seen as demonic and nature an evil to be tamed, a young apprentice hunter comes to Ireland with her father to wipe out the last pack. But when she saves a wild native girl, their friendship leads her to discover the world of the Wolfwalkers and transform her into the very thing her father is tasked to destroy.', 'https://image.tmdb.org/t/p/w500/vqGiNbdc2sDwsnivMMYzwAoSSu6.jpg', 'https://image.tmdb.org/t/p/original/3zTbERSBLh7waK9811RTKGAcG86.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
