INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1437985, 'Open Season 2', 2025, 1, 'France', 'French', 'Two years after moving to the French countryside and seeing hunting banned, Adelaide and Simon discover that living close to nature can be rewarding, peaceful... and unbelievably boring. Desperate to make new friends, they''re overjoyed when Bernard''s witty, wealthy son Stan and his smart, aristocratic wife Bennie move to town—with kids the same age as theirs. But what seems like a gift from heaven turns out to be a Trojan horse: Stan and Bennie are die-hard coursers, determined to hunt on horseback with their hounds wherever they please. Chaos ensues. The clash becomes a full-blown war as Stan buys up land, bribes the locals, and plans to turn the forest into a playground for the ultra-rich. With help from Bernard and his old hunting buddies, can Addie and Simon rally the villagers and spark a rural revolt to save their peaceful corner of the world?', 'https://image.tmdb.org/t/p/w500/cjy5vFVr2FmkNVjHaeKROFgJxGH.jpg', 'https://image.tmdb.org/t/p/original/255neTizAGgmgHPXQenAL3bITLT.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
