INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1404684, 'Juste une illusion', 2026, 116, 'France', 'French', '1985. Vincent, almost 13, lives in the suburbs of Paris in a middle-class family, between a distant older brother and parents in constant conflict. Although he is no longer a child and not yet an adult, the film follows his reflections and doubts about identity, friendship, family, and his questions about religion, desire, and love.', 'https://image.tmdb.org/t/p/w500/my4QdEBuhYpYLR4M7AkJWJGcxxx.jpg', 'https://image.tmdb.org/t/p/original/jCCqS6qKVhofuQCKBfsRvP3zP7R.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
