INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (662723, 'Danur: The Last Chapter', 2026, 98, 'Indonesia', 'Sundanese', 'After years of separation from her ghost friends, Risa goes on with her life, closing the door to any communication with any ghosts. However, things change when her sister, Riri, is proposed. In an old theater and begins acting strangely in the time leading to her wedding. Not only does Riri change, but Risa also begins experiencing a series of strange events, as if she’s experiencing a painful death repeatedly. Risa suspects that this was happening because her ghost friends, Peter and his friends, were trying to convey something.', 'https://image.tmdb.org/t/p/w500/khU4SeP5G1et7q20tL8oNXJGiHz.jpg', 'https://image.tmdb.org/t/p/original/lzUbj964SGiFdGSzX1DJRn3bzCE.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
