INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (62201, 'Shahenshah', 1988, 180, 'India', 'Hindi', 'Inspector Srivastav is framed by a wily and cunning gangster, J.K., and unable to prove his innocence, hangs himself, leaving behind his wife, and son, Vijay. Years later, Vijay has grown up and has joined the police force as an Inspector. Unlike his dad, he is corrupt and does accept bribes to turn a nelson''s eye to crime. The City Police are assigned the task of apprehending a customed man called "Shahenshah", who operates at night and targets, tries and kills gangsters in a "Judge and Executioner "style. No one knows the real identity of Shahenshah, as he is feared by the police department, and respected by the poor and middle-class.', 'https://image.tmdb.org/t/p/w500/2ZUpj73MzEh2YwVzJNVUqBSu2LZ.jpg', 'https://image.tmdb.org/t/p/original/qDyFe7gMnom72qfUEYzWrgwB4ss.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
