INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (592350, 'My Hero Academia: Heroes Rising', 2019, 104, 'Japan', 'Japanese', 'Class 1-A visits Nabu Island where they finally get to do some real hero work. The place is so peaceful that it''s more like a vacation... until they''re attacked by a villain with an unfathomable Quirk! His power is eerily familiar, and it looks like Shigaraki had a hand in the plan. But with All Might retired and citizens'' lives on the line, there''s no time for questions. Deku and his friends are the next generation of heroes, and they''re the island''s only hope.', 'https://image.tmdb.org/t/p/w500/kpWsIkfXrnQ1pmR79qAHHq7DPxc.jpg', 'https://image.tmdb.org/t/p/original/9guoVF7zayiiUq5ulKQpt375VIy.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
