INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1464533, 'Suzuki=Bakudan', 2025, 136, 'Japan', 'Japanese', 'An unemployed man named Suzuki is taken in by police after breaking a booze vending machine. When he predicts the explosions of two bombs and claims there are more, the police start to investigate him as a terrorist. However, Suzuki first claims to know about the bombs through psychic clairvoyance, and then claims he was hypnotized to forget. He gives hints about the bombs with riddles while riling up his interrogators, especially senior detective Kiyomiya and his junior Ruike. Things seem to be connected to a disgraced cop named Hasebe, who committed suicide after a scandal some years ago. But is Suzuki actually the perpetrator behind the bombs or not?', 'https://image.tmdb.org/t/p/w500/7d4Gb3R1W6OByg46V5TSCNbbpUW.jpg', 'https://image.tmdb.org/t/p/original/qcqIsy9TUlyibicNgycMookPE04.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
