INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1461254, 'Salmokji: Whispering Water', 2026, 96, 'South Korea', 'Korean', 'An unidentified figure is captured in a street-view image of Salmokji, a remote reservoir. A reshoot is required to contain the situation—but a sense of dread surrounds the location, and no one is eager to return. Despite the unease, Su-in leads the crew in place of her senior colleague, who previously vanished after visiting the area. The shoot quickly begins to unravel as crew members experience disturbing phenomena that defy explanation. As the deep end of Salmokji reveals traces of something lurking beneath the surface, the team is forced to confront a presence that refuses to remain unseen—and a truth that should have never been surfaced.', 'https://image.tmdb.org/t/p/w500/bOl0rJ86WWxVYlQlGttHhHuYiPQ.jpg', 'https://image.tmdb.org/t/p/original/u0pvmpa4iUbVm6QqR4MRLwnaYOe.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
