INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1368519, 'Cinque secondi', 2025, 105, 'Italy', 'French', 'Who is that scruffy-looking guy who lives alone in the renovated stables of Villa Guelfi? He spends his days doing nothing and avoiding contact with everyone. And when he realizes that a community of young people has settled illegally in the villa and is dedicated to caring for the abandoned countryside and vineyards, he gets nervous and wants to chase them away. They are students, recent graduates, agronomists, and among them is Matilde, who was born there and worked in the vineyard with her grandfather, Count Guelfo Guelfi, as a child. They too are intrigued by this misanthropic gentleman with a mysterious past: why does he live there alone and refuse to have contact with anyone? As the seasons pass, the conflict with this community of young men and women turns into coexistence, and eventually into an alliance. And Adriano finds himself looking after, in his brusque way, the young Countess Matilde, who is pregnant by one of the young men...', 'https://image.tmdb.org/t/p/w500/5hPjY75ddE90l6XzfAC6zrMRnNg.jpg', 'https://image.tmdb.org/t/p/original/g5njzG7BzbqudncIKt9zrGYkVtw.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
