INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1303657, 'Allegro Pastell', 2026, 100, 'Germany', 'German', 'In the summer of 2018, novelist Tanja Arnheim and web designer Jerome Daimler have a seemingly ideal long-distance relationship in the heat of Berlin, the idyll of an inherited bungalow in the Hessian Main Valley and many train journeys in between. But the carefully cultivated balance of trust and detachment between the two hyper-reflective millennials is shaken when Tanja realizes on the night of her thirtieth birthday that the relationship could become existential.', 'https://image.tmdb.org/t/p/w500/dm7gUD4RfxokQ533Y8DIweLjUT2.jpg', 'https://image.tmdb.org/t/p/original/vOBjs6laaX6APuOH0KVweAU4vkd.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
