INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (193972, 'Living Marble', 1910, 6, 'Austria', 'No Language', 'Four gentlemen are talking in a beer-garden; during a short absence of one of them, who pretends to be an art lover, the others decide to make a prank on him. When he comes back, one them invites the "square" bourgeois to his home, pretexting to show him an art catalog. The men pay their drinks and leave, but the three friends convene later, and they have paid a young female model to be there, too.', 'https://image.tmdb.org/t/p/w500/h0dSHEbb0EiYt6NPYrnkyR0uj7U.jpg', NULL) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
