INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1464829, 'Brand New Landscape', 2025, 115, 'Japan', 'Japanese', 'In the ever-changing landscape of redeveloping Shibuya, Tokyo, Ren works as a delivery driver for moth orchids. Haunted by the childhood loss of his mother, Yumiko, to suicide, he has long been estranged from his father, Hajime, a landscape designer. One day, during a routine delivery, Ren unexpectedly comes face to face with Hajime…', 'https://image.tmdb.org/t/p/w500/o66wEQiXC3AqKDB3GzTphWygDPO.jpg', 'https://image.tmdb.org/t/p/original/lIq0JaqCyjsl643hoT8yZWSDXJt.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
