INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1202152, 'The Myth of Maracuda', 2025, 90, 'Russia', 'Danish', 'The son of Chief Marakud should become a real warrior, but he does not know how to hunt at all and disappoints his father. Marakuda goes alone into the forest and finds the sacred bird Tink, which gives him the gift of understanding the language of animals and birds. Marakuda and Tink return home with honors. The boy does not know that according to tradition, the sacred bird must be sacrificed for the prosperity of the tribe.', 'https://image.tmdb.org/t/p/w500/8QhhL7q8CP9FxUgMR2eEP9oymXG.jpg', 'https://image.tmdb.org/t/p/original/5s98bd53qqFYZa9ACL4vD48ebsT.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
