INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1072742, 'When Morning Comes, I Feel Empty', 2023, 76, 'Japan', 'Japanese', '24-year-old Nozomi quit her job at an ad agency and now works part-time at a convenience store. Her ordinary days are enlivened by funny and kind co-workers but her heart is troubled because she cannot tell her parents about her situation and she is haunted by her failure to meet the excessive demands at her previous workplace. One day, her former junior high school classmate Kanako appears and Nozomi begins to articulate how she feels.', 'https://image.tmdb.org/t/p/w500/tQvme7eBY44yQGULn30Qi7jr6xs.jpg', 'https://image.tmdb.org/t/p/original/lEk9GBEhzS8ezGx9ZBBoYJHKzvK.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
