INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1302848, 'Class Reunion', 2025, 94, 'France', 'French', 'Feeling nostalgic about their high school days, Hervé, Maxime, and Jordy decide to host a grand reunion party to reconnect and celebrate their 30-year graduation anniversary. However, their idealised memories clash with reality: no one wants to come, especially their former classmates Anne and Marion, who are determined to sabotage the event. For the first time, the trio face a harsh realisation – could it be that all this time they’ve been nothing but a bunch of pretentious jerks? Determined to make amends, they embark on a hilarious quest to prove to the world and themselves that they can be better men.', 'https://image.tmdb.org/t/p/w500/9bj75Pb7sUFE6IeDM33V1GwbagY.jpg', 'https://image.tmdb.org/t/p/original/4QJu5gehRwc5krZt5RythpvhBux.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
