INSERT INTO movies (id, title, release_year, duration_minutes, country, language, synopsis, poster_image_url, backdrop_image_url) VALUES (1335666, 'Glenrothan', 2026, 99, 'United Kingdom', 'English', 'After 35 years in Chicago, Donal reluctantly returns to the Scottish Highlands to reconcile with his estranged older brother Sandy. Sandy needs Donal to take over the family''s whisky distillery or he''ll be forced to sell and give up on the family''s legacy. But their reunion forces the brothers to confront the past and the real reason Donal left Glenrothan.', 'https://image.tmdb.org/t/p/w500/gNKQETNDN9sVxpiayzF9bTw5a5q.jpg', 'https://image.tmdb.org/t/p/original/dAU3mJzDLWWZyndByhV7hSIfBiK.jpg') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year, duration_minutes = EXCLUDED.duration_minutes, country = EXCLUDED.country, language = EXCLUDED.language, synopsis = EXCLUDED.synopsis, poster_image_url = EXCLUDED.poster_image_url, backdrop_image_url = EXCLUDED.backdrop_image_url;
